vector<bool> solve(const string& s, const vector<string>& arr) {
    const int n = (int)s.length();
    vector<int> prefix(n), suffix(n);
    int c0 = 0, c1 = 0;
    for (int i = 0, j = n - 1; i < n; i++, j--) {
        prefix[i] = c1 += s[i] == '1';
        suffix[j] = c0 += s[j] == '0';
    }
    vector<bool> ret;
    for (const auto& q : arr) {
        bool valid = true;
        c0 = 0, c1 = 0;
        for (int i = 0, j = n - 1; i < n; i++, j--)
            if ((c1 += q[i] == '1') > prefix[i] || (c0 += q[j] == '0') > suffix[j]) {
                valid = false;
                break;
            }
        ret.push_back(valid);
    }
    return ret;
}

int main() {
    solve("101100",{"?110?1","111???"}); // 1,0
}
