def can_transform(src, target):
    if len(src) != len(target):
        return False

    # Count the digits in src and the fixed digits in target.
    s0, s1 = src.count("0"), src.count("1")
    t0, t1, wild = target.count("0"), target.count("1"), target.count("?")

    # The target (after replacing '?') must have exactly s0 zeros and s1 ones.
    if t0 > s0 or t1 > s1 or (s0 - t0) + (s1 - t1) != wild:
        return False

    # Greedily replace '?' in target: use zeros first to "delay" ones.
    zeros_needed = s0 - t0
    new_target = []
    for ch in target:
        if ch == "?":
            if zeros_needed:
                new_target.append("0")
                zeros_needed -= 1
            else:
                new_target.append("1")
        else:
            new_target.append(ch)
    new_target = "".join(new_target)

    # Check that at every prefix the count of 1's in src is <= count of 1's in new_target.
    ones_src = ones_tgt = 0
    for s_digit, t_digit in zip(src, new_target):
        if s_digit == "1":
            ones_src += 1
        if t_digit == "1":
            ones_tgt += 1
        if ones_src > ones_tgt:
            return False

    return True
